from typing import List

class FoodRatings:

    def __init__(self, foods: List[str], cuisines: List[str], ratings: List[int]):
        self.foods = {food: (cuisine, rating) for food, cuisine, rating in zip(foods, cuisines, ratings)}
        self.cuisines = {}
        for food, (cuisine, _) in self.foods.items():
            if cuisine not in self.cuisines:
                self.cuisines[cuisine] = []
            self.cuisines[cuisine].append((food, ratings[self.foods.keys().index(food)]))

    def changeRating(self, food: str, newRating: int) -> None:
        cuisine, _ = self.foods[food]
        self.foods[food] = (cuisine, newRating)
        self.cuisines[cuisine].sort(key=lambda x: (-x[1], x[0]))

    def highestRated(self, cuisine: str) -> str:
        return self.cuisines[cuisine][0][0]
